dashboard.definition:
{
  "title": "Sample Dashboard \u2014 Application Portal",
  "description": "Sample portal-style dashboard with 8 large category cards. Every icon is a bundled SVG referenced directly via splunk.image (no icon_library.icon_library viz). Demonstrates the SVG-asset pattern for navigation hubs.",
  "defaults": {},
  "dataSources": {},
  "inputs": {},
  "visualizations": {
    "viz_canvas_bg": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#F5F5F7",
        "strokeColor": "transparent"
      }
    },
    "viz_header_title": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "extraLarge",
        "markdown": "# Application Portal\n\n*Sample dashboard \u00b7 8 categories \u00b7 click a card to navigate*"
      }
    },
    "viz_header_subtitle": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#6E6E73",
        "fontFamily": "Helvetica",
        "fontSize": "small",
        "markdown": "Icons rendered directly from the bundled SVG catalog via `splunk.image` \u2014 no `icon_library.icon_library` viz instances on this page. Each card's icon URL points to `/static/app/icon_library/icons/<category>/<name>.svg`."
      }
    },
    "viz_shadow_0": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#E8E8ED",
        "strokeColor": "transparent"
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_card_0": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_icon_0": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/action/dashboard.svg",
        "preserveAspectRatio": "xMidYMid meet"
      }
    },
    "viz_text_0": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "**Dashboards**\n\n<span style=\"color:#6E6E73;font-size:13px;\">Visualize anything</span>\n\n<span style=\"color:#06B6D4;font-size:12px;font-weight:600;\">248 SAVED</span>"
      }
    },
    "viz_shadow_1": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#E8E8ED",
        "strokeColor": "transparent"
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_card_1": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_icon_1": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/action/search.svg",
        "preserveAspectRatio": "xMidYMid meet"
      }
    },
    "viz_text_1": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "**Searches**\n\n<span style=\"color:#6E6E73;font-size:13px;\">Ad-hoc and saved searches</span>\n\n<span style=\"color:#06B6D4;font-size:12px;font-weight:600;\">1.2K SAVED</span>"
      }
    },
    "viz_shadow_2": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#E8E8ED",
        "strokeColor": "transparent"
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_card_2": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_icon_2": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/social/notifications_active.svg",
        "preserveAspectRatio": "xMidYMid meet"
      }
    },
    "viz_text_2": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "**Alerts**\n\n<span style=\"color:#6E6E73;font-size:13px;\">Real-time notification rules</span>\n\n<span style=\"color:#06B6D4;font-size:12px;font-weight:600;\">47 ACTIVE</span>"
      }
    },
    "viz_shadow_3": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#E8E8ED",
        "strokeColor": "transparent"
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_card_3": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_icon_3": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/action/article.svg",
        "preserveAspectRatio": "xMidYMid meet"
      }
    },
    "viz_text_3": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "**Reports**\n\n<span style=\"color:#6E6E73;font-size:13px;\">Scheduled PDFs and summaries</span>\n\n<span style=\"color:#06B6D4;font-size:12px;font-weight:600;\">89 SCHEDULED</span>"
      }
    },
    "viz_shadow_4": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#E8E8ED",
        "strokeColor": "transparent"
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_card_4": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_icon_4": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/editor/table_chart.svg",
        "preserveAspectRatio": "xMidYMid meet"
      }
    },
    "viz_text_4": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "**Lookups**\n\n<span style=\"color:#6E6E73;font-size:13px;\">CSV and KV-store enrichment tables</span>\n\n<span style=\"color:#06B6D4;font-size:12px;font-weight:600;\">34 LOOKUPS</span>"
      }
    },
    "viz_shadow_5": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#E8E8ED",
        "strokeColor": "transparent"
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_card_5": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_icon_5": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/action/code.svg",
        "preserveAspectRatio": "xMidYMid meet"
      }
    },
    "viz_text_5": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "**Macros**\n\n<span style=\"color:#6E6E73;font-size:13px;\">Reusable SPL snippets</span>\n\n<span style=\"color:#06B6D4;font-size:12px;font-weight:600;\">62 MACROS</span>"
      }
    },
    "viz_shadow_6": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#E8E8ED",
        "strokeColor": "transparent"
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_card_6": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_icon_6": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/navigation/apps.svg",
        "preserveAspectRatio": "xMidYMid meet"
      }
    },
    "viz_text_6": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "**Apps**\n\n<span style=\"color:#6E6E73;font-size:13px;\">Installed Splunk apps</span>\n\n<span style=\"color:#06B6D4;font-size:12px;font-weight:600;\">18 INSTALLED</span>"
      }
    },
    "viz_shadow_7": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#E8E8ED",
        "strokeColor": "transparent"
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_card_7": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        20,
        20,
        20,
        20
      ]
    },
    "viz_icon_7": {
      "type": "splunk.image",
      "options": {
        "backgroundColor": "transparent",
        "src": "/static/app/icon_library/icons/action/settings.svg",
        "preserveAspectRatio": "xMidYMid meet"
      }
    },
    "viz_text_7": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "**Settings**\n\n<span style=\"color:#6E6E73;font-size:13px;\">Server and user configuration</span>\n\n<span style=\"color:#06B6D4;font-size:12px;font-weight:600;\">ADMIN ONLY</span>"
      }
    },
    "viz_stats_card": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#FFFFFF",
        "strokeColor": "#D2D2D7",
        "strokeWidth": 1
      },
      "cornerRadius": [
        16,
        16,
        16,
        16
      ]
    },
    "viz_stats_md": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#1D1D1F",
        "fontFamily": "Helvetica",
        "fontSize": "default",
        "markdown": "### Quick stats this week\n\n**248** dashboards rendered \u00b7 **412 k** searches dispatched \u00b7 **89** reports delivered \u00b7 **47** active alert rules \u00b7 **5.4 TB** ingested"
      }
    },
    "viz_footer": {
      "type": "splunk.markdown",
      "options": {
        "backgroundColor": "transparent",
        "fontColor": "#6E6E73",
        "fontFamily": "Helvetica",
        "fontSize": "extraSmall",
        "markdown": "*Sample dashboard for icon_library \u00b7 8 SVG icons rendered via `splunk.image` from the bundled catalog (`/static/app/icon_library/icons/<category>/<name>.svg`) \u00b7 all stats are mocked.*"
      }
    }
  },
